toolArgs.file_text:
@using sv_4b26423cd207406fb72c1c8b55e7b845.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                @if (!string.IsNullOrWhiteSpace(channel.Description))
                {
                    <span class="channel-desc">@Truncate(channel.Description, 40)</span>
                }
            </li>
        }
    </ul>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2b2d31;
    color: #ccc;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #1e1f22;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    display: flex;
    flex-direction: column;
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 8px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #35373c;
}

.channel-item.active {
    background: #404249;
    color: #fff;
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.93rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

