arguments.file_text:
@page "/chat"
@layout sv_4b26423cd207406fb72c1c8b55e7b845.Components.Chat.ChatLayout
@rendermode InteractiveServer
@using sv_4b26423cd207406fb72c1c8b55e7b845.Services
@using sv_4b26423cd207406fb72c1c8b55e7b845.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="main-header">
                <h2># @_activeChannel.Name</h2>
                <span class="header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-area" @onscroll="HandleScroll" @ref="_messageAreaRef">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in _messages)
                {
                    <MessageBubble Message="msg"
                                   ReplyCount="GetReplyCount(msg.Id)"
                                   OnOpenThread="OpenThread"
                                   OnReact="HandleReaction" />
                }
                @if (_messages.Count == 0 && !_loading)
                {
                    <div class="empty-state">No messages yet. Start the conversation!</div>
                }
            </div>

            <MessageInput Placeholder="@($"Message #{_activeChannel.Name}")"
                          ButtonLabel="Send"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadReplies = [];
    private Dictionary<int, int> _replyCounts = new();

    private Channel? _activeChannel;
    private int _activeChannelId;
    private Message? _threadRootMessage;
    private bool _threadOpen;
    private bool _loading;
    private bool _loadingMore;
    private bool _allMessagesLoaded;

    private ElementReference _messageAreaRef;

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _loading = true;
        _allMessagesLoaded = false;

        CloseThreadSilent();

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await BuildReplyCounts();
        _loading = false;

        await ChatService.MarkChannelReadAsync(channelId);

        // Update unread count in the local list
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannel.Id, content, null);
        _messages.Add(msg);
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top pagination is handled via JS interop in production.
        // For simplicity, we provide a fallback: detect when we're near the top.
        // In a real app you'd use IJSRuntime to check scrollTop.
        // Here we expose a manual "load more" via the loading indicator area.
    }

    private async Task LoadOlderMessages()
    {
        if (_loadingMore || _allMessagesLoaded || _activeChannel is null) return;

        _loadingMore = true;
        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);
        if (older.Count < PageSize)
        {
            _allMessagesLoaded = true;
        }
        _messages.InsertRange(0, older);
        await BuildReplyCounts();
        _loadingMore = false;
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        CloseThreadSilent();
    }

    private void CloseThreadSilent()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update reply count
        _replyCounts[_threadRootMessage.Id] = _threadReplies.Count;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update: add/increment the reaction locally
        var msg = _messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private int GetReplyCount(int messageId) =>
        _replyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task BuildReplyCounts()
    {
        // Identify thread starters: messages with no ReplyToId that others reply to
        var rootIds = _messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct();

        foreach (var rootId in rootIds)
        {
            if (!_replyCounts.ContainsKey(rootId))
            {
                _replyCounts[rootId] = _messages.Count(m => m.ReplyToId == rootId);
            }
        }

        // Also fetch thread summaries for messages that appear to be thread starters
        // from the loaded batch — check any message that has ReplyToId == null
        await Task.CompletedTask;
    }
}

