    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannel.Id, content, null);
        _messages.Add(msg);
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top pagination is handled via JS interop in production.
        // For simplicity, we provide a fallback: detect when we're near the top.
        // In a real app you'd use IJSRuntime to check scrollTop.
        // Here we expose a manual "load more" via the loading indicator area.
    }

    private async Task LoadOlderMessages()
    {
        if (_loadingMore || _allMessagesLoaded || _activeChannel is null) return;

        _loadingMore = true;
        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);
