toolArgs.file_text:
.chat-layout {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.chat-main.thread-open {
    /* Shrinks when thread is open */
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

/* Main header */
.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.main-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.header-desc {
    font-size: 0.82rem;
    color: #777;
}

/* Message area */
.message-area {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #999;
    font-size: 1rem;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #999;
    font-size: 1.1rem;
}

